// === CONFIGURE HERE ===
var ALPACA_KEY_ID     = 'PASTE_YOUR_KEY_ID_HERE';
var ALPACA_SECRET_KEY = 'PASTE_YOUR_SECRET_KEY_HERE';
var MAX_POSITIONS     = 3;
// =======================

// Handle both wrapped {body:{...}} and flat {ticker:...} payloads
var body   = ($json.body !== undefined) ? $json.body : $json;
var ticker = String(body.ticker || '').toUpperCase().trim();
var price  = parseFloat(body.price) || 0;
var signal = String(body.signal || '').toUpperCase().trim();

if (!ticker || price <= 0) return [];
if (signal !== 'BUY' && signal !== 'EXIT') return [];

var alpacaHeaders = {
  'APCA-API-KEY-ID': ALPACA_KEY_ID,
  'APCA-API-SECRET-KEY': ALPACA_SECRET_KEY
};

// EXIT path: pass through — Exit Handler node does cancel + sell
if (signal === 'EXIT') {
  return [{ json: { ticker, price, signal, ALPACA_KEY_ID, ALPACA_SECRET_KEY } }];
}

// BUY path: guard against existing positions
var heldTickers = [];
try {
  var pos = await $helpers.httpRequest({
    method: 'GET',
    url: 'https://paper-api.alpaca.markets/v2/positions',
    headers: alpacaHeaders
  });
  for (var pi = 0; pi < pos.length; pi++) {
    heldTickers.push(pos[pi].symbol);
  }
} catch(e) {}

if (heldTickers.indexOf(ticker) >= 0) return [];  // already holding
if (heldTickers.length >= MAX_POSITIONS) return [];  // at capacity

var stop = parseFloat((price * 0.92).toFixed(2));
var t1   = parseFloat((price * 1.15).toFixed(2));
var t2   = parseFloat((price * 1.30).toFixed(2));
var t3   = parseFloat((price * 1.60).toFixed(2));

return [{ json: {
  ticker, price, signal,
  stop, t1, t2, t3,
  qty: 10, qty_t1: 3, qty_t2: 3, qty_t3: 4,
  ALPACA_KEY_ID, ALPACA_SECRET_KEY
} }];

