// Cancel all open orders for ticker, then market sell full position
var ALPACA_KEY_ID     = $json.ALPACA_KEY_ID;
var ALPACA_SECRET_KEY = $json.ALPACA_SECRET_KEY;
var ticker            = $json.ticker;
var price             = $json.price;

var alpacaHeaders = {
  'APCA-API-KEY-ID': ALPACA_KEY_ID,
  'APCA-API-SECRET-KEY': ALPACA_SECRET_KEY
};

// 1. Get all open orders for this ticker
var orders = [];
try {
  orders = await $helpers.httpRequest({
    method: 'GET',
    url: 'https://paper-api.alpaca.markets/v2/orders?status=open&symbols=' + ticker,
    headers: alpacaHeaders
  });
} catch(e) {}

// 2. Cancel each one
var cancelledCount = 0;
for (var i = 0; i < orders.length; i++) {
  try {
    await $helpers.httpRequest({
      method: 'DELETE',
      url: 'https://paper-api.alpaca.markets/v2/orders/' + orders[i].id,
      headers: alpacaHeaders
    });
    cancelledCount++;
  } catch(e) {}
}

// 3. Get current position qty
var posQty = 0;
try {
  var pos = await $helpers.httpRequest({
    method: 'GET',
    url: 'https://paper-api.alpaca.markets/v2/positions/' + ticker,
    headers: alpacaHeaders
  });
  posQty = parseInt(pos.qty) || 0;
} catch(e) {}

if (posQty <= 0) return [];

// 4. Market sell entire remaining position
try {
  await $helpers.httpRequest({
    method: 'POST',
    url: 'https://paper-api.alpaca.markets/v2/orders',
    headers: Object.assign({}, alpacaHeaders, { 'Content-Type': 'application/json' }),
    body: JSON.stringify({
      symbol: ticker,
      qty: posQty,
      side: 'sell',
      type: 'market',
      time_in_force: 'day'
    })
  });
} catch(e) {}

return [{ json: {
  ticker,
  qty_sold: posQty,
  exit_price: price,
  orders_cancelled: cancelledCount,
  ALPACA_KEY_ID,
  ALPACA_SECRET_KEY
} }];

